mapper.insert:
insert into `dispute` (
    dispute_no, order_id, initiator_id, respondent_id, admin_id, dispute_type,
    reason, detail, evidence_json, freeze_amount, status, result_type, resolution_note,
    resolved_at, closed_at, version, created_at, updated_at
) values (
    #{disputeNo}, #{orderId}, #{initiatorId}, #{respondentId}, #{adminId}, #{disputeType},
    #{reason}, #{detail}, #{evidenceJson}, #{freezeAmount}, #{status}, #{resultType}, #{resolutionNote},
    #{resolvedAt}, #{closedAt}, #{version}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from `dispute`
where initiator_id = #{userId}
   or respondent_id = #{userId}
order by id desc
